/**
 * Inter (Regular + Bold), subsetted to Latin + Czech diacritics and
 * base64-encoded for jsPDF addFileToVFS/addFont. jsPDF core fonts
 * (Helvetica etc.) only cover WinAnsi/Latin-1, which does not include
 * Czech caron/ring characters -- feeding them to doc.text() with a core
 * font silently drops or mis-renders those glyphs. Sourced from Google
 * Fonts' legacy subsetting endpoint (css2?family=Inter&text=...), the
 * only public endpoint that still serves raw .ttf (modern requests get
 * woff2, which jsPDF cannot consume directly) -- OFL-1.1 licensed.
 */

export const INTER_REGULAR_TTF_BASE64 =
  "";

export const INTER_BOLD_TTF_BASE64 =
  "";
